from dataclasses import dataclass, field
from datetime import date
from typing import Literal

Track = Literal["T1_LITERACY", "T2_PRACTITIONER", "T3_BUILDER"]
Status = Literal["ENROLLED", "IN_PROGRESS", "PENDING_GATE", "CERTIFIED", "DROPPED"]

@dataclass
class LearningCohort:
    cohort_id: str
    track: Track
    role_family: str          # e.g. "finance", "engineering", "legal"
    facilitator: str
    start_date: date
    target_end_date: date
    max_participants: int = 20
    participants: list[str] = field(default_factory=list)  # employee IDs

    def is_open(self) -> bool:
        return len(self.participants) < self.max_participants

    def size_check(self) -> str:
        n = len(self.participants)
        if n < 12:
            return f"UNDER-SUBSCRIBED ({n} participants — minimum is 12 for effective peer learning)"
        if n > 20:
            return f"OVER-SUBSCRIBED ({n} participants — split into two cohorts)"
        return f"OK ({n} participants)"

    def enrol(self, employee_id: str) -> bool:
        if not self.is_open():
            return False
        if employee_id not in self.participants:
            self.participants.append(employee_id)
        return True

@dataclass
class TransitionPlan:
    employee_id: str
    current_role: str
    target_role: str
    displacement_risk: Literal["LOW", "MEDIUM", "HIGH", "CRITICAL"]
    transition_start: date
    target_completion: date
    hr_partner: str
    manager: str
    skill_gaps: list[str]           # from skills gap analysis
    development_actions: list[str]  # specific learning interventions
    milestones: list[dict]          # {date, description, status}

    def months_remaining(self) -> int:
        from datetime import date as dt
        today = dt.today()
        delta = (self.target_completion.year - today.year) * 12 +                 (self.target_completion.month - today.month)
        return max(delta, 0)

    def pct_gaps_addressed(self) -> float:
        if not self.skill_gaps:
            return 1.0
        addressed = len([a for a in self.development_actions
                         if any(gap.lower() in a.lower() for gap in self.skill_gaps)])
        return min(addressed / len(self.skill_gaps), 1.0)

    def is_on_track(self) -> bool:
        # For CRITICAL risk: must have ≥50% gaps addressed within 90 days
        if self.displacement_risk == "CRITICAL":
            return self.pct_gaps_addressed() >= 0.5 or self.months_remaining() > 9
        return self.pct_gaps_addressed() >= 0.3 or self.months_remaining() > 6

    def status_summary(self) -> str:
        track = "ON TRACK" if self.is_on_track() else "AT RISK"
        return (
            f"{self.employee_id}: {self.current_role} → {self.target_role} "
            f"[{self.displacement_risk} risk] — {track} "
            f"({self.pct_gaps_addressed():.0%} gaps addressed, "
            f"{self.months_remaining()} months remaining)"
        )

@dataclasses.dataclass
class EmployeeLearningRecord:
    employee_id: str
    role_family: str
    t1_status: Status = "ENROLLED"
    t1_completion_date: date | None = None
    t2_status: Status = "ENROLLED"
    t2_completion_date: date | None = None
    t3_eligible: bool = False
    t3_status: Status | None = None
    t3_completion_date: date | None = None
    transition_plan: TransitionPlan | None = None

    def current_track(self) -> Track | None:
        if self.t1_status != "CERTIFIED":
            return "T1_LITERACY"
        if self.t2_status != "CERTIFIED":
            return "T2_PRACTITIONER"
        if self.t3_eligible:
            return "T3_BUILDER"
        return None  # fully certified for their role

    def is_lagging(self, days_since_program_launch: int) -> bool:
        # T1 should be complete within 90 days
        if days_since_program_launch > 90 and self.t1_status != "CERTIFIED":
            return True
        # T2 should be complete within 180 days
        if days_since_program_launch > 180 and self.t2_status != "CERTIFIED":
            return True
        return False


@dataclasses.dataclass
class ReskillingSummary:
    business_unit: str
    employees: list[EmployeeLearningRecord]
    days_since_launch: int

    def t1_completion_rate(self) -> float:
        certified = sum(1 for e in self.employees if e.t1_status == "CERTIFIED")
        return certified / len(self.employees) if self.employees else 0.0

    def t2_completion_rate(self) -> float:
        eligible = [e for e in self.employees if e.t2_status is not None]
        certified = sum(1 for e in eligible if e.t2_status == "CERTIFIED")
        return certified / len(eligible) if eligible else 0.0

    def lagging_employees(self) -> list[str]:
        return [e.employee_id for e in self.employees
                if e.is_lagging(self.days_since_launch)]

    def health_status(self) -> str:
        t1 = self.t1_completion_rate()
        lagging = len(self.lagging_employees())
        if t1 >= 0.9 and lagging == 0:
            return "HEALTHY"
        if t1 >= 0.7 and lagging <= 3:
            return "NEEDS_ATTENTION"
        return "AT_RISK"

    def executive_summary(self) -> str:
        return (
            f"{self.business_unit}: "
            f"T1 {self.t1_completion_rate():.0%} | "
            f"T2 {self.t2_completion_rate():.0%} | "
            f"{len(self.lagging_employees())} lagging | "
            f"Status: {self.health_status()}"
        )
